DELIMITER $$
--
-- Procedimentos
--
CREATE DEFINER=`km_system`@`localhost` PROCEDURE `sp_atualizar_metas` (IN `p_ano` INT)   BEGIN
    DECLARE v_km_total_eventos DECIMAL(12,2);
    DECLARE v_km_meta DECIMAL(12,2);
    DECLARE v_km_registrado DECIMAL(12,2);
    DECLARE v_percentual DECIMAL(5,2);
    DECLARE v_status VARCHAR(20);
    DECLARE v_mes INT;
    DECLARE v_km_eventos_mes DECIMAL(12,2);
    DECLARE v_km_meta_mes DECIMAL(12,2);
    DECLARE v_km_reg_mes DECIMAL(12,2);
    DECLARE v_pct_mes DECIMAL(5,2);
    
    -- Calcula KM total dos eventos no ano
    SELECT COALESCE(SUM(km_awarded), 0) INTO v_km_total_eventos
    FROM events
    WHERE active = 1 AND YEAR(event_date) = p_ano;
    
    -- Calcula KM registrado pelos usuários no ano
    SELECT COALESCE(SUM(e.km_awarded + a.km_extra), 0) INTO v_km_registrado
    FROM attendances a
    INNER JOIN events e ON e.id = a.event_id
    WHERE YEAR(e.event_date) = p_ano;
    
    -- Calcula meta (80%)
    SET v_km_meta = v_km_total_eventos * 0.8;
    
    -- Calcula percentual
    IF v_km_meta > 0 THEN
        SET v_percentual = ROUND((v_km_registrado / v_km_meta) * 100, 2);
        IF v_percentual > 100 THEN
            SET v_percentual = 100;
        END IF;
    ELSE
        SET v_percentual = 0;
    END IF;
    
    -- Define status
    IF v_percentual >= 100 THEN
        SET v_status = 'superado';
    ELSEIF v_percentual >= 80 THEN
        SET v_status = 'atingido';
    ELSE
        SET v_status = 'pendente';
    END IF;
    
    -- Insere ou atualiza meta anual
    INSERT INTO metas_anuais (ano, km_total_eventos, km_meta, km_registrado, percentual_atingido, status)
    VALUES (p_ano, v_km_total_eventos, v_km_meta, v_km_registrado, v_percentual, v_status)
    ON DUPLICATE KEY UPDATE
        km_total_eventos = v_km_total_eventos,
        km_meta = v_km_meta,
        km_registrado = v_km_registrado,
        percentual_atingido = v_percentual,
        status = v_status;
    
    -- Atualiza metas mensais
    SET v_mes = 1;
    WHILE v_mes <= 12 DO
        -- KM total dos eventos no mês
        SELECT COALESCE(SUM(km_awarded), 0) INTO v_km_eventos_mes
        FROM events
        WHERE active = 1 AND YEAR(event_date) = p_ano AND MONTH(event_date) = v_mes;
        
        -- KM registrado no mês
        SELECT COALESCE(SUM(e.km_awarded + a.km_extra), 0) INTO v_km_reg_mes
        FROM attendances a
        INNER JOIN events e ON e.id = a.event_id
        WHERE YEAR(e.event_date) = p_ano AND MONTH(e.event_date) = v_mes;
        
        -- Meta mensal
        SET v_km_meta_mes = v_km_eventos_mes * 0.8;
        
        -- Percentual mensal
        IF v_km_meta_mes > 0 THEN
            SET v_pct_mes = ROUND((v_km_reg_mes / v_km_meta_mes) * 100, 2);
            IF v_pct_mes > 100 THEN
                SET v_pct_mes = 100;
            END IF;
        ELSE
            SET v_pct_mes = 0;
        END IF;
        
        -- Insere ou atualiza
        INSERT INTO metas_mensais (ano, mes, km_total_eventos_mes, km_meta_mes, km_registrado_mes, percentual_atingido)
        VALUES (p_ano, v_mes, v_km_eventos_mes, v_km_meta_mes, v_km_reg_mes, v_pct_mes)
        ON DUPLICATE KEY UPDATE
            km_total_eventos_mes = v_km_eventos_mes,
            km_meta_mes = v_km_meta_mes,
            km_registrado_mes = v_km_reg_mes,
            percentual_atingido = v_pct_mes;
        
        SET v_mes = v_mes + 1;
    END WHILE;
    
    -- Registra no histórico
    INSERT INTO metas_historico (ano, km_total_eventos, km_meta, km_registrado, percentual_atingido)
    VALUES (p_ano, v_km_total_eventos, v_km_meta, v_km_registrado, v_percentual);
    
END$$

DELIMITER ;

