CREATE TABLE `whatsapp_grupos` (
  `id` int(10) UNSIGNED NOT NULL,
  `nome` varchar(100) NOT NULL COMMENT 'Nome do grupo',
  `group_id` varchar(100) NOT NULL COMMENT 'ID do grupo no WhatsApp',
  `descricao` varchar(255) DEFAULT NULL,
  `graduacoes` longtext DEFAULT NULL COMMENT 'Array de graduações que recebem mensagens neste grupo. NULL = todos' CHECK (json_valid(`graduacoes`)),
  `ativo` tinyint(1) DEFAULT 1,
  `created_at` timestamp NULL DEFAULT current_timestamp()
